arguments.typescript:
// Attempt direct async function calls as top-level awaitable globals
const context = await getSchedulingContext();
const result  = await proposeMeetingSlot({
  localTimezone:   context.localTimezone,
  boliviaTimezone: context.boliviaTimezone,
});

return {
  proposedStartIso: result.proposedStartIso,
  proposedEndIso:   result.proposedEndIso,
  localTimezone:    result.localTimezone,
  boliviaTimezone:  result.boliviaTimezone,
  rationale:        result.rationale,
};

async function main() {
  const ctx = await sandbox.getSchedulingContext();

  const result = await sandbox.proposeMeetingSlot({
    localTimezone: ctx.localTimezone,
    boliviaTimezone: ctx.boliviaTimezone,
  });

  return {
    proposedStartIso: result.proposedStartIso,
    proposedEndIso: result.proposedEndIso,
    localTimezone: result.localTimezone,
    boliviaTimezone: result.boliviaTimezone,
    rationale: result.rationale,
  };
}

return await main();

